var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"MN No. SFMC001M000179-03\\n<color=#ffd34c>3급 요인</color> 열람 승인 자료\\n부록: 관련자 면담기록","JPN":"MN No. SFMC001M000179-03\\n<color=#ffd34c>3級要因</color> 閲覧承認資料\\n付録: 関係者面談記録","ENG":"(ENG)MN No. SFMC001M000179-03\\n<color=#ffd34c>3급 요인</color> 열람 승인 자료\\n부록: 관련자 면담기록","TWN":"(TWN)MN No. SFMC001M000179-03\\n<color=#ffd34c>3급 요인</color> 열람 승인 자료\\n부록: 관련자 면담기록"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"다음 안건입니다.\\n이전에 지시하셨던 추가 조사가 끝났습니다.","JPN":"次の案件です。\\n以前に指示した追加調査が終わりました。","ENG":"(ENG)다음 안건입니다.\\n이전에 지시하셨던 추가 조사가 끝났습니다.","TWN":"(TWN)다음 안건입니다.\\n이전에 지시하셨던 추가 조사가 끝났습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"응? 내가 추가 조사까지 지시했던가?","JPN":"うん?私が追加調査まで指示したのか?","ENG":"(ENG)응? 내가 추가 조사까지 지시했던가?","TWN":"(TWN)응? 내가 추가 조사까지 지시했던가?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"정확히는 포섭할 방법을 찾아 보라고 하셨죠.","JPN":"正確には抱きこむ方法を探してみなさいとしたんです。","ENG":"(ENG)정확히는 포섭할 방법을 찾아 보라고 하셨죠.","TWN":"(TWN)정확히는 포섭할 방법을 찾아 보라고 하셨죠."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"예산을 추가로 타내려면 가끔씩 침소봉대도 필요하지 않겠습니까.","JPN":"予算を追加でせがんでもらおうとすれば時たま針小棒大も必要でないですか。","ENG":"(ENG)예산을 추가로 타내려면 가끔씩 침소봉대도 필요하지 않겠습니까.","TWN":"(TWN)예산을 추가로 타내려면 가끔씩 침소봉대도 필요하지 않겠습니까."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"솔직하게 얘기한다고 정상 참작이 될 건 아니네만......","JPN":"率直に話すと情状酌量になるのはアニネマン......","ENG":"(ENG)솔직하게 얘기한다고 정상 참작이 될 건 아니네만......","TWN":"(TWN)솔직하게 얘기한다고 정상 참작이 될 건 아니네만......"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"뭐, 오늘은 남은 업무도 없으니 여유롭게 들어 봄세.","JPN":"何、今日は残った業務もないから余裕のあるようにきいてみる勢。","ENG":"(ENG)뭐, 오늘은 남은 업무도 없으니 여유롭게 들어 봄세.","TWN":"(TWN)뭐, 오늘은 남은 업무도 없으니 여유롭게 들어 봄세."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"알겠습니다. 먼저 동종업계 종사자들 사이에서의 평판을 수집했습니다.","JPN":"わかりました。先に同種業界従事者の間での評判を収集しました。","ENG":"(ENG)알겠습니다. 먼저 동종업계 종사자들 사이에서의 평판을 수집했습니다.","TWN":"(TWN)알겠습니다. 먼저 동종업계 종사자들 사이에서의 평판을 수집했습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"현장 동행 시 만족도가 상당히 높더군요.","JPN":"現場同行時満足度がかなり高いですね。","ENG":"(ENG)현장 동행 시 만족도가 상당히 높더군요.","TWN":"(TWN)현장 동행 시 만족도가 상당히 높더군요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"의외로군. 요즘 용병들은 가방끈 긴 사람에게 사나울 것 같은데.","JPN":"案外だな。最近傭兵はかばん紐長い人に荒いようであるが。","ENG":"(ENG)의외로군. 요즘 용병들은 가방끈 긴 사람에게 사나울 것 같은데.","TWN":"(TWN)의외로군. 요즘 용병들은 가방끈 긴 사람에게 사나울 것 같은데."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그런 걸 점잖은 표현으로 편견이라고 합니다.","JPN":"そんなものを重厚な表現で偏見と言います。","ENG":"(ENG)그런 걸 점잖은 표현으로 편견이라고 합니다.","TWN":"(TWN)그런 걸 점잖은 표현으로 편견이라고 합니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"대 침식전은 다른 작전보다 하이 리스크, 하이 리턴이 전제됩니다.","JPN":"大侵食前は他の作戦よりハイリスク、ハイリターンが前提されます。","ENG":"(ENG)대 침식전은 다른 작전보다 하이 리스크, 하이 리턴이 전제됩니다.","TWN":"(TWN)대 침식전은 다른 작전보다 하이 리스크, 하이 리턴이 전제됩니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"언제 어디서 비명횡사할지 모르는 만큼 기왕이면 옆에 믿음직스러운 동료가 있어 주길 바라죠.","JPN":"いつどこで非命横死するかもしれないほどどうせなら横に頼もしい仲間があってくださってくれ。","ENG":"(ENG)언제 어디서 비명횡사할지 모르는 만큼 기왕이면 옆에 믿음직스러운 동료가 있어 주길 바라죠.","TWN":"(TWN)언제 어디서 비명횡사할지 모르는 만큼 기왕이면 옆에 믿음직스러운 동료가 있어 주길 바라죠."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"게다가 수틀리면 자기 뒤통수에 총구를 겨눌지도 모르는데 굳이 쌀쌀맞게 굴 것도 없습니다.","JPN":"さらにうまく行かなければ自分後頭部に銃口を狙うかも知れないが敢えて冷ややかにふるまうこともないです。","ENG":"(ENG)게다가 수틀리면 자기 뒤통수에 총구를 겨눌지도 모르는데 굳이 쌀쌀맞게 굴 것도 없습니다.","TWN":"(TWN)게다가 수틀리면 자기 뒤통수에 총구를 겨눌지도 모르는데 굳이 쌀쌀맞게 굴 것도 없습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"확실히 이런 건 현장을 겪은 사람이 잘 아는구만.","JPN":"確実にこうしたのは現場を経験した人がよく分かるんだな。","ENG":"(ENG)확실히 이런 건 현장을 겪은 사람이 잘 아는구만.","TWN":"(TWN)확실히 이런 건 현장을 겪은 사람이 잘 아는구만."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그리고 인텔리라는 요소는 오히려 메리트가 될 수 있습니다.","JPN":"そしてインテリという要素はむしろメリットになることができます。","ENG":"(ENG)그리고 인텔리라는 요소는 오히려 메리트가 될 수 있습니다.","TWN":"(TWN)그리고 인텔리라는 요소는 오히려 메리트가 될 수 있습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"지식이 필요하단 거겠지. 경험만으론 대체 못하니까.","JPN":"知識が必要であるということだろう。経験だけでは一体できないから。","ENG":"(ENG)지식이 필요하단 거겠지. 경험만으론 대체 못하니까.","TWN":"(TWN)지식이 필요하단 거겠지. 경험만으론 대체 못하니까."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"네. 아는 게 많을수록 살아남을 확률도 높아지니까요.\\n사격 솜씨와는 다른 영역입니다.","JPN":"はい。分かるのが多いほど生き延びる確率も高くなるからです。\\n射撃腕前とは他の領域です。","ENG":"(ENG)네. 아는 게 많을수록 살아남을 확률도 높아지니까요.\\n사격 솜씨와는 다른 영역입니다.","TWN":"(TWN)네. 아는 게 많을수록 살아남을 확률도 높아지니까요.\\n사격 솜씨와는 다른 영역입니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"하지만 그것과 별개로 현재는 단독으로 활동 중이더군요.\\n주로 중소 규모 침식지대의 침식체 소탕 작전을 수주하고 있습니다.","JPN":"しかしそれと別個で現在は単独で活動中ですね。\\n主に中小規模寝食地帯の侵食体掃討作戦を受注しています。","ENG":"(ENG)하지만 그것과 별개로 현재는 단독으로 활동 중이더군요.\\n주로 중소 규모 침식지대의 침식체 소탕 작전을 수주하고 있습니다.","TWN":"(TWN)하지만 그것과 별개로 현재는 단독으로 활동 중이더군요.\\n주로 중소 규모 침식지대의 침식체 소탕 작전을 수주하고 있습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그래? 단독 행동은 위험하지 않나?\\n자네 보고대로라면 팀을 꾸리지 못할 것도 없을 텐데.","JPN":"そう?単独行動は危なくないか?\\n君の宝庫大ローラ面チームを立てることができないこともないつもりだったのですが。","ENG":"(ENG)그래? 단독 행동은 위험하지 않나?\\n자네 보고대로라면 팀을 꾸리지 못할 것도 없을 텐데.","TWN":"(TWN)그래? 단독 행동은 위험하지 않나?\\n자네 보고대로라면 팀을 꾸리지 못할 것도 없을 텐데."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"본인 의향이겠죠.","JPN":"本人意向でしょう。","ENG":"(ENG)본인 의향이겠죠.","TWN":"(TWN)본인 의향이겠죠."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"메이슨? 아, 그 약삭빠른 녀석?","JPN":"メイスン?あ、そのずるいやつ?","ENG":"(ENG)메이슨? 아, 그 약삭빠른 녀석?","TWN":"(TWN)메이슨? 아, 그 약삭빠른 녀석?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"어떻게 잊겠어. 내 머리숱이 홀랑 타 버렸을 때 같이 있었던 놈을.","JPN":"どう忘れる。私の髪の毛がすっかり乗ってしまった時一緒にあった遊ぶことを。","ENG":"(ENG)어떻게 잊겠어. 내 머리숱이 홀랑 타 버렸을 때 같이 있었던 놈을.","TWN":"(TWN)어떻게 잊겠어. 내 머리숱이 홀랑 타 버렸을 때 같이 있었던 놈을."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"신참 주제에 실력은 끝내 줬지. 내가 본 녀석들 중에선 한 손에 꼽혔어.\\n아, 그러니까 이 손가락 두 짝 거덜난 손에 말이야.","JPN":"新参身の程に実力は終えたの。私が見た野郎ども中では一つかみに数えられた。\\nア、そうするからこの指二俵つぶれた手に言葉だ。","ENG":"(ENG)신참 주제에 실력은 끝내 줬지. 내가 본 녀석들 중에선 한 손에 꼽혔어.\\n아, 그러니까 이 손가락 두 짝 거덜난 손에 말이야.","TWN":"(TWN)신참 주제에 실력은 끝내 줬지. 내가 본 녀석들 중에선 한 손에 꼽혔어.\\n아, 그러니까 이 손가락 두 짝 거덜난 손에 말이야."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"하지만 오래 같이 일할 타입은 아냐.","JPN":"しかし長く一緒に仕事をするタイプではない。","ENG":"(ENG)하지만 오래 같이 일할 타입은 아냐.","TWN":"(TWN)하지만 오래 같이 일할 타입은 아냐."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"왜냐고? 그야 돈에 목숨 건 타입이 아니거든.","JPN":"なぜかと?そりゃお金に命ことはタイプではなかったら。","ENG":"(ENG)왜냐고? 그야 돈에 목숨 건 타입이 아니거든.","TWN":"(TWN)왜냐고? 그야 돈에 목숨 건 타입이 아니거든."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"이봐, 우린 돈 때문에 총 들고 침식체랑 부대끼는 거야.\\n좋아서 그놈들 체액으로 샤워하는 게 아니라고.","JPN":"ほら、私たちはお金のために鉄砲入って侵食体ともまれることなの。\\n良くてあいつ体液でシャワーをあびるのではないと。","ENG":"(ENG)이봐, 우린 돈 때문에 총 들고 침식체랑 부대끼는 거야.\\n좋아서 그놈들 체액으로 샤워하는 게 아니라고.","TWN":"(TWN)이봐, 우린 돈 때문에 총 들고 침식체랑 부대끼는 거야.\\n좋아서 그놈들 체액으로 샤워하는 게 아니라고."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그런데 그 녀석은 돈이 중요한 게 아니었어.\\n가끔 꼭 뭘 알고 싶어 안달이 난 교수 나리처럼 굴었지.","JPN":"ところでそのやつはお金が重要なのではなかった。\\nたまに必ず何を知りたくてアン月が出た教授旦那のようにふるまったの。","ENG":"(ENG)그런데 그 녀석은 돈이 중요한 게 아니었어.\\n가끔 꼭 뭘 알고 싶어 안달이 난 교수 나리처럼 굴었지.","TWN":"(TWN)그런데 그 녀석은 돈이 중요한 게 아니었어.\\n가끔 꼭 뭘 알고 싶어 안달이 난 교수 나리처럼 굴었지."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"용병 노릇을 하고 있지만 우리랑은 뿌리부터 달라.\\n아마 요새도 혼자 일할걸. 살아 있으면 말이야.","JPN":"傭兵役をしているが私たちとは根から違う。\\n多分この頃も一人で働くの。生きていれば。","ENG":"(ENG)용병 노릇을 하고 있지만 우리랑은 뿌리부터 달라.\\n아마 요새도 혼자 일할걸. 살아 있으면 말이야.","TWN":"(TWN)용병 노릇을 하고 있지만 우리랑은 뿌리부터 달라.\\n아마 요새도 혼자 일할걸. 살아 있으면 말이야."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"돈에 목숨을 걸지 않는다.......\\n곤란하군.","JPN":"お金に命をかけない.......\\n困るね。","ENG":"(ENG)돈에 목숨을 걸지 않는다.......\\n곤란하군.","TWN":"(TWN)돈에 목숨을 걸지 않는다.......\\n곤란하군."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"돈만 아는 성격이면 박사 학위까지 취득하지도 않았겠죠.","JPN":"お金だけ分かる性格なら博士の学位まで取得しなかったでしょう。","ENG":"(ENG)돈만 아는 성격이면 박사 학위까지 취득하지도 않았겠죠.","TWN":"(TWN)돈만 아는 성격이면 박사 학위까지 취득하지도 않았겠죠."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그래서 앞의 증언을 채록한 이후 성장 배경을 확인해 봤습니다.","JPN":"それで前の証言を採録してから成長背景を確認してみました。","ENG":"(ENG)그래서 앞의 증언을 채록한 이후 성장 배경을 확인해 봤습니다.","TWN":"(TWN)그래서 앞의 증언을 채록한 이후 성장 배경을 확인해 봤습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};